+      } catch (e) {
+        if (backupPath) await copyFile(backupPath, rvfaPath).catch(() => {});
+        return failResult(sec, [`Post-patch verify error: ${(e as Error).message}`],
+          { backupPath, newSize: newRvfa.length });
+      }
+    }
